fn solve(nums: Vec<i64>) -> Vec<i64> {
    let n = nums.len();
    if n <= 1 {
        return vec![0; n];
    }

    let mut answer = vec![0; n];

    for i in 0..n {
        let current_is_odd = nums[i] % 2 != 0;
        let mut count = 0;

        for j in (i + 1)..n {
            let next_is_odd = nums[j] % 2 != 0;

            // Check if parity is different
            if current_is_odd != next_is_odd {
                count += 1;
            }
        }
        answer[i] = count;
    }

    answer
}
